 1	import * as React from 'react';
 2	import {
 3	  IBM_SCALE_NAMESPACE,
 4	  IBM_SCALE_OPERATOR_NAME,
 5	} from '@odf/core/constants';
 6	import { ClusterKind, RemoteClusterKind } from '@odf/core/types/scale';
 7	import {
 8	  ClusterServiceVersionKind,
 9	  ClusterServiceVersionModel,
10	  getName,
11	} from '@odf/shared';
12	import { useK8sList } from '@odf/shared/hooks';
13	import { ClusterModel, RemoteClusterModel } from '@odf/shared/models/scale';
14	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
15	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
16	import { referenceForModel } from '@odf/shared/utils';
17	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
18	import {
19	  Card,
20	  CardBody,
21	  CardHeader,
22	  CardTitle,
23	  DescriptionList,
24	} from '@patternfly/react-core';
25	
26	const DetailsCard: React.FC<{}> = () => {
27	  const { t } = useCustomTranslation();
28	
29	  const [clusters, clustersLoaded, clustersError] =
30	    useK8sList<ClusterKind>(ClusterModel);
31	  const [remoteClusters] = useK8sList<RemoteClusterKind>(RemoteClusterModel);
32	
33	  const [csvs] = useK8sWatchResource<ClusterServiceVersionKind[]>({
34	    kind: referenceForModel(ClusterServiceVersionModel),
35	    namespaced: true,
36	    isList: true,
37	    namespace: IBM_SCALE_NAMESPACE,
38	  });
39	
40	  const ibmCSV = csvs?.find((csv) =>
41	    csv.metadata.name.includes(IBM_SCALE_OPERATOR_NAME)
42	  );
43	  const operatorVersion = ibmCSV?.spec?.version;
44	  const cluster = clusters?.[0];
45	  const remoteCluster = remoteClusters?.[0];
46	
47	  const clusterName = getName(cluster);
48	  const endpointUrl = remoteCluster?.spec?.gui?.hosts?.[0];
49	
50	  return (
51	    <Card>
52	      <CardHeader>
53	        <CardTitle>{t('Details')}</CardTitle>
54	      </CardHeader>
55	      <CardBody>
56	        <DescriptionList>
57	          <DetailItem
58	            key="cluster-name"
59	            title={t('Cluster name')}
60	            isLoading={!clustersLoaded}
61	            error={clustersError}
62	          >
63	            {clusterName || 'N/A'}
64	          </DetailItem>
65	          <DetailItem key="version" title={t('Version')}>
66	            {operatorVersion || 'N/A'}
67	          </DetailItem>
68	          <DetailItem key="created-on" title={t('Created on')}>
69	            {cluster?.metadata?.creationTimestamp}
70	          </DetailItem>
71	          <DetailItem key="url" title={t('Remote cluster endpoint URL')}>
72	            {endpointUrl}
73	          </DetailItem>
74	        </DescriptionList>
75	      </CardBody>
76	    </Card>
77	  );
78	};
79	
80	export default DetailsCard;

